def extract_docstring(code):
    lines = code.split('\n')
    in_def = False
    for i, line in enumerate(lines):
        stripped = line.strip()
        if stripped.startswith('def '):
            in_def = True
            continue
        if in_def and stripped:
            if stripped.startswith('"""') or stripped.startswith("'''"):
                end = stripped[3:].find(stripped[:3])
                if end != -1:
                    return stripped[3:end+3]
                else:
                    doc_lines = [stripped[3:]]
                    for j in range(i+1, len(lines)):
                        if lines[j].strip().endswith(stripped[:3]):
                            doc_lines.append(lines[j].strip()[:-3])
                            return '\n'.join(doc_lines)
                        doc_lines.append(lines[j].rstrip())
                    return '\n'.join(doc_lines)
            else:
                return ''
    return ''

